'use client';

import { useState, type FormEvent, Suspense } from 'react';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import { Mail, Lock, ArrowRight, Apple } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { useAuth } from '@/context/AuthContext';

function LoginContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const { login, loginWithGoogle, loginWithApple } = useAuth();
    const [formData, setFormData] = useState({
        email: '',
        password: '',
    });
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e: FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');
        
        try {
            const success = await login(formData.email, formData.password, 'customer');
            if (success) {
                const from = searchParams.get('from') || '/';
                router.replace(from);
            } else {
                setError('Invalid email, password, or unauthorized role');
            }
        } catch (err) {
            setError('An error occurred during login.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleGoogleLogin = async () => {
        setIsLoading(true);
        setError('');
        try {
            const success = await loginWithGoogle('customer');
            if (success) {
                const from = searchParams.get('from') || '/';
                router.replace(from);
            } else {
                setError('Google sign-in failed or unauthorized role');
            }
        } catch (err) {
            setError('An error occurred during Google login.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleAppleLogin = async () => {
        setIsLoading(true);
        setError('');
        try {
            const success = await loginWithApple('customer');
            if (success) {
                const from = searchParams.get('from') || '/';
                router.replace(from);
            } else {
                setError('Apple sign-in failed or unauthorized role');
            }
        } catch (err) {
            setError('An error occurred during Apple login.');
        } finally {
            setIsLoading(false);
        }
