        }
    },
    verify: async () => {
        if (isFirebaseConfigured && auth) {
            return new Promise((resolve) => {
                const unsubscribe = onAuthStateChanged(auth, (user) => {
                    unsubscribe();
                    if (user) {
                        resolve({ valid: true });
                    } else {
                        resolve({ valid: false });
                    }
                });
            });
        } else {
            const token = localStorage.getItem('token') || '';
            if (token.startsWith('mock-jwt-token-') || token.startsWith('fb-jwt-')) {
